import { useContext, useState } from 'react';
import { CandidateContext } from '../context/CandidateContext';
import CandidateForm from './CandidateForm';

export default function CandidateList() {
  const { candidates, loading, error, addCandidate, updateCandidate, deleteCandidate } = useContext(CandidateContext);
  const [showForm, setShowForm] = useState(false);
  const [editCandidate, setEditCandidate] = useState(null);

  if (loading) return <p>Loading...</p>;
  if (error) return <p className="text-red-500">Error: {error}</p>;

  const handleAdd = () => {
    setEditCandidate(null);
    setShowForm(true);
  };

  const handleEdit = (candidate) => {
    setEditCandidate(candidate);
    setShowForm(true);
  };

  const handleSave = async (formData) => {
    if (editCandidate) {
      await updateCandidate(editCandidate.id, formData);
    } else {
      await addCandidate(formData);
    }
    setShowForm(false);
  };

  return (
    <div>
      <button onClick={handleAdd} className="mb-4 px-4 py-2 bg-green-600 text-white rounded">
        Add Candidate
      </button>
      <table className="min-w-full border">
        <thead className="bg-gray-100">
          <tr>
            <th className="px-2 py-1 border">Name</th>
            <th className="px-2 py-1 border">Email</th>
            <th className="px-2 py-1 border">Phone</th>
            <th className="px-2 py-1 border">Position</th>
            <th className="px-2 py-1 border">Actions</th>
          </tr>
        </thead>
        <tbody>
          {candidates.map((c) => (
            <tr key={c.id} className="hover:bg-gray-50">
              <td className="border px-2 py-1">{c.name}</td>
              <td className="border px-2 py-1">{c.email}</td>
              <td className="border px-2 py-1">{c.phone}</td>
              <td className="border px-2 py-1">{c.position}</td>
              <td className="border px-2 py-1 space-x-2">
                <button onClick={() => handleEdit(c)} className="text-blue-600">Edit</button>
                <button onClick={() => deleteCandidate(c.id)} className="text-red-600">Delete</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
      {showForm && (
        <CandidateForm
          initial={editCandidate}
          onSave={handleSave}
          onClose={() => setShowForm(false)}
        />
      )}
    </div>
  );
}
